import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './styles.css';

const rootElement = document.getElementById('root');

if (!rootElement) {
  throw new Error('Root element #root was not found');
}

ReactDOM.createRoot(rootElement).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);

:root {
  color-scheme: light;
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  line-height: 1.5;
  font-weight: 400;
  color: #e5eefb;
  background: #0b1220;
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

* {
  box-sizing: border-box;
}

html,
body,
#root {
  margin: 0;
  min-height: 100%;
}

body {
  min-width: 320px;
  min-height: 100vh;
  background:
    radial-gradient(circle at top left, rgba(58, 120, 255, 0.18), transparent 32%),
    linear-gradient(180deg, #0b1220 0%, #10192d 100%);
}

button {
  font: inherit;
}

#root {
  min-height: 100vh;
}

.app-shell {
  display: grid;
  grid-template-columns: 280px minmax(0, 1fr);
  min-height: 100vh;
}

.sidebar {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
  padding: 1.5rem;
  background: rgba(6, 11, 22, 0.78);
  border-right: 1px solid rgba(148, 163, 184, 0.16);
  backdrop-filter: blur(16px);
}

.sidebar__brand {
  display: flex;
  align-items: center;
  gap: 0.875rem;
}

.sidebar__logo {
  display: inline-grid;
  place-items: center;
  width: 2.75rem;
  height: 2.75rem;
  border-radius: 0.9rem;
  background: linear-gradient(135deg, #5b8cff, #8b5cf6);
  color: white;
  font-weight: 700;
}

.sidebar__eyebrow,
.topbar__eyebrow,
.editor__eyebrow,
.sidebar__section-label {
  margin: 0;
  color: #94a3b8;
  font-size: 0.78rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.sidebar__title,
.topbar__title,
.editor__panel h3 {
  margin: 0;
}

.sidebar__section {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.document-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 0.625rem;
}

.document-list__item,
.topbar__actions button {
  width: 100%;
  border: 1px solid rgba(148, 163, 184, 0.14);
  border-radius: 0.9rem;
  background: rgba(15, 23, 42, 0.68);
  color: inherit;
  padding: 0.875rem 1rem;
  text-align: left;
  cursor: pointer;
}

.document-list__item[aria-current='page'] {
  border-color: rgba(91, 140, 255, 0.6);
  background: rgba(37, 99, 235, 0.16);
}

.document-list__title {
  display: block;
  font-weight: 600;
}

.document-list__status {
  display: block;
  color: #94a3b8;
  font-size: 0.88rem;
}

.workspace {
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
  min-width: 0;
}

.topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 1.25rem 1.5rem;
  border-bottom: 1px solid rgba(148, 163, 184, 0.16);
  background: rgba(10, 15, 28, 0.72);
  backdrop-filter: blur(16px);
}

.topbar__actions {
  display: flex;
  gap: 0.75rem;
}

.topbar__actions button {
  width: auto;
  text-align: center;
  padding-inline: 1rem;
}

.editor {
  padding: 1.5rem;
}

.editor__panel {
  min-height: calc(100vh - 7rem);
  border: 1px dashed rgba(148, 163, 184, 0.35);
  border-radius: 1.25rem;
  background: rgba(15, 23, 42, 0.5);
  padding: 1.5rem;
  display: grid;
  align-content: start;
  gap: 0.75rem;
}

.editor__panel p {
  margin: 0;
  max-width: 60ch;
  color: #cbd5e1;
}

@media (max-width: 860px) {
  .app-shell {
    grid-template-columns: 1fr;
  }

  .sidebar {
    border-right: 0;
    border-bottom: 1px solid rgba(148, 163, 184, 0.16);
  }

  .editor__panel {
    min-height: 24rem;
  }
}

